class Solution {
public:
    bool canPartitionKSubsets(vector<int>& nums, int k) {
        int sum = 0;
        for (int num : nums) sum += num;
        if (sum % k != 0) return false;
        int target = sum / k;
        vector<bool> dp(1 << nums.size(), false);
        dp[0] = true;
        vector<int> sums(1 << nums.size(), 0);
        for (int i = 0; i < (1 << nums.size()); i++) {
            if (!dp[i]) continue;
            for (int j = 0; j < nums.size(); j++) {
                if (!(i & (1 << j))) continue;
                int next = i | (1 << j);
                if (sums[i] + nums[j] <= target) {
                    sums[next] = sums[i] + nums[j];
                    dp[next] = true;
                }
                if (sums[i] + nums[j] == target) {
                    sums[next] = 0;
                    dp[next] = dp[next] || dp[i];
                }
            }
        }
        return dp[(1 << nums.size()) - 1];
    }
};
